sql:
SELECT COUNT(*) AS total_policies
FROM cookie_policies
WHERE cookie_id = (SELECT cookie_id FROM cookies ORDER BY cookie_id ASC LIMIT 1);

SELECT COUNT(cookie_id) AS total_inactive_cookies
FROM cookies
WHERE is_active = 0 AND cookie_id NOT IN (SELECT cookie_id FROM cookie_policies);

SELECT name
FROM cookies
WHERE duration = (SELECT MAX(duration) FROM cookies);

SELECT name, duration
FROM cookies
WHERE type = 'First Party';

external_knowledge:
- A third-party cookie is a cookie that is set by a website other than the one the user is currently visiting; 
- A cookie is considered active if it has not expired or been deleted; 
- A one-day lifespan means the cookie remains active for one day after it is set.

sql:
SELECT expiration_date
FROM cookies
WHERE name = 'NID' AND host = 'google.com';
